// Split leaderboard entries into individual items for processing
const leaderboard = $input.first().json;
const entries = Array.isArray(leaderboard) ? leaderboard : [leaderboard];
return entries.map(entry => ({ json: entry }));

// Filter for recent trades (last 5 minutes) with size > $10K
const FIVE_MINUTES_MS = 5 * 60 * 1000;
const cutoff = Date.now() - FIVE_MINUTES_MS;
const MIN_SIZE = 10000;

const results = [];

for (const item of $input.all()) {
  const trades = Array.isArray(item.json) ? item.json : [item.json];
  for (const trade of trades) {
    const tradeTime = new Date(trade.timestamp || trade.createdAt || 0).getTime();
    const size = parseFloat(trade.size || '0');
    if (tradeTime > cutoff && size > MIN_SIZE) {
      results.push({
        json: {
          proxyWallet: trade.user || trade.proxyWallet,
          conditionId: trade.conditionId || trade.market,
          tokenId: trade.tokenId || trade.assetId,
          side: trade.side,
          size: size,
          price: parseFloat(trade.price || '0'),
          timestamp: trade.timestamp || trade.createdAt
        }
      });
    }
  }
}

if (results.length === 0) {
  return [];
}

return results;

// Format alert payload for each qualifying whale trade
const WEBHOOK_URL = $env.WEBHOOK_URL || 'http://localhost:3000';

const results = [];
for (const item of $input.all()) {
  const market = item.json;
  // Carry forward trade data from earlier nodes
  const trade = item.json._trade || item.json;

  const outcomePrices = JSON.parse(market.outcomePrices || '[0, 0]');
  const currentPrice = parseFloat(outcomePrices[0]) || 0;
  const clobTokenIds = JSON.parse(market.clobTokenIds || '["", ""]');
  const tokenId = clobTokenIds[0] || trade.tokenId || '';
  const side = trade.side === 'BUY' ? 'bought' : 'sold';
  const sizeStr = (trade.size || 0).toLocaleString();

  results.push({
    json: {
      webhookUrl: WEBHOOK_URL + '/api/alert',
      payload: {
        category: 'whales',
        title: `Top trader ${side} $${sizeStr} on "${market.question}"`,
        body: `Whale ${side} at $${(trade.price || currentPrice).toFixed(2)}. Market: "${market.question}". Total market volume: $${parseInt(market.volume || '0').toLocaleString()}.`,
        market: {
          conditionId: market.conditionId || trade.conditionId,
          question: market.question || 'Unknown market',
          tokenId: tokenId,
          currentPrice: currentPrice
        },
        urgent: false,
        metadata: {
          traderWallet: trade.proxyWallet,
          tradeSize: trade.size
        }
      }
    }
  });
}

return results;
